export async function syncProjects(opts?: { full?: boolean }): Promise<ChunkSyncResult> {
  const raw = getRawDb();

  if (opts?.full) {
    raw.exec("DELETE FROM project_chunks");
    raw.exec("DELETE FROM vec_projects");
  }

  // Collect files from both locations
  const projectFiles = findMdFiles(PROJECTS_ROOT);
  const docFiles = findMdFiles(DOCS_ROOT);
  const allFiles = [
    ...projectFiles.map(f => ({ path: f, root: PROJECTS_ROOT })),
    ...docFiles.map(f => ({ path: f, root: DOCS_ROOT })),
  ];

  let filesProcessed = 0;
  let chunksCreated = 0;
  const pendingEmbeds: { chunkId: number; content: string }[] = [];

  for (const { path: filePath, root } of allFiles) {
    const rawContent = readFileSync(filePath, "utf-8");
    const hash = hashFile(rawContent);
    const fileName = filePath.split(/[/\\]/).pop() || "unknown.md";
    const project = detectProject(filePath, root);
    const docType = detectDocType(fileName);
    const sourcePath = relative(fromRoot(), filePath).replace(/\\/g, "/");

    // Check if chunks exist with matching hash
    const existing = raw.prepare(
      "SELECT file_hash FROM project_chunks WHERE source_path = ? LIMIT 1"
    ).get(sourcePath) as { file_hash: string } | null;

    if (existing && existing.file_hash === hash && !opts?.full) continue;

    // Delete old chunks
    const oldIds = raw.prepare(
      "SELECT id FROM project_chunks WHERE source_path = ?"
    ).all(sourcePath) as { id: number }[];

    if (oldIds.length > 0) {
      raw.exec("DELETE FROM project_chunks WHERE source_path = ?", [sourcePath] as any);
      for (const { id } of oldIds) {
        try { raw.exec("DELETE FROM vec_projects WHERE chunk_id = ?", [id] as any); } catch {}
      }
    }

    // Extract frontmatter for status
    const parsed = parseFile(filePath);
    const status = parsed.frontmatter.status ?? null;
    const tags = parsed.tags;

    // Chunk
    const chunks = chunkMarkdown(rawContent, fileName);
    const ts = now();

    for (const chunk of chunks) {
      const result = raw.prepare(`
        INSERT INTO project_chunks (project, doc_type, source_path, section_name, content, line_start, line_end, tags, status, token_count, file_hash, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      `).run(
        project, docType, sourcePath, chunk.sectionName,
        chunk.content, chunk.lineStart, chunk.lineEnd,
        tags, status, chunk.tokenCount, hash, ts, ts
      );

      const chunkId = Number(result.lastInsertRowid);
      pendingEmbeds.push({ chunkId, content: chunk.content });
      chunksCreated++;
    }

