/**
 * brain/sync.ts — File sync engine for brain.db
 *
 * Scans vault memory and reference MD files, hashes them,
 * and upserts changed rows into SQLite. Supports incremental
 * sync (hash diff) and full rebuild.
 */

import { readdirSync, readFileSync, existsSync, statSync } from "fs";
import { join, relative, basename, dirname } from "path";
import { createHash } from "crypto";
import { eq } from "drizzle-orm";
import { fromRoot } from "../paths.js";
import { getDb, getRawDb } from "../sqlite.js";
import { parseFrontmatter, getBody } from "../frontmatter.js";
import { memories, references, referenceChunks, projectChunks, syncMeta } from "./schema.js";
import { rebuildFts } from "./fts.js";
import { chunkMarkdown } from "./chunker.js";
import { embedBatch, vectorToBuffer, estimateTokens, EMBEDDING_CONFIG } from "../embeddings.js";

const VAULT_STUDIO = fromRoot("vault", "studio");
const MEMORY_ROOT = join(VAULT_STUDIO, "memory");
const REFS_ROOT = join(VAULT_STUDIO, "references");
const PROJECTS_ROOT = join(VAULT_STUDIO, "projects");
const DOCS_ROOT = fromRoot("vault", "notes", "docs");

export interface SyncStatus {
  memoriesChanged: number;
  memoriesTotal: number;
  refsChanged: number;
  refsTotal: number;
  removed: number;
}

interface ParsedFile {
  title: string;
  content: string;
  tags: string | null;
  frontmatter: Record<string, any>;
  body: string;
}

// ─── Helpers ─────────────────────────────────────────────────

function hashFile(content: string): string {
  return createHash("sha256").update(content).digest("hex").slice(0, 16);
}

function now(): string {
  return new Date().toISOString();
}

/** Recursively find all .md files under a directory */
function findMdFiles(dir: string): string[] {
  const results: string[] = [];
  if (!existsSync(dir)) return results;

  const entries = readdirSync(dir, { withFileTypes: true });
  for (const entry of entries) {
    const fullPath = join(dir, entry.name);
    if (entry.isDirectory()) {
      results.push(...findMdFiles(fullPath));
    } else if (entry.name.endsWith(".md")) {
      results.push(fullPath);
    }
  }
  return results;
}

/** Parse an MD file into structured parts */
function parseFile(filePath: string): ParsedFile {
  const raw = readFileSync(filePath, "utf-8");
  const fm = parseFrontmatter(raw);
  const body = getBody(raw);

  const title =
    fm.name || fm.title || extractFirstHeading(body) || basename(filePath, ".md");
  const tags = fm.tags ? (Array.isArray(fm.tags) ? fm.tags.join(", ") : String(fm.tags)) : null;

  return { title, content: raw, tags, frontmatter: fm, body };
}

function extractFirstHeading(body: string): string | null {
  const match = body.match(/^#+\s+(.+)$/m);
  return match ? match[1].trim() : null;
}

// ─── Memory sync ─────────────────────────────────────────────

/** Determine agent name and tier from file path */
function parseMemoryPath(filePath: string): { agent: string; tier: string } | null {
  const rel = relative(MEMORY_ROOT, filePath).replace(/\\/g, "/");
  const parts = rel.split("/");
  // Expected: {agent}/{tier}/file.md or {agent}/file.md (root-level like memory-index)
  if (parts.length < 2) return null;

  const agent = parts[0];

  // Exclude raw context files — they have their own sync path
  if (agent === "raw") return null;

  const tier = parts.length >= 3 ? parts[1] : "root";

  // Skip archive files
  if (tier === "archive") return null;

  return { agent, tier };
}

/**
 * Sync all memory files into brain.db.
 * @param full - If true, drops and rebuilds. If false, incremental hash diff.
 */
export async function syncMemories(opts?: { full?: boolean }): Promise<number> {
  const db = getDb();
  const raw = getRawDb();
  const files = findMdFiles(MEMORY_ROOT);
  let changed = 0;

  if (opts?.full) {
    raw.exec("DELETE FROM memories");
    raw.exec("DELETE FROM sync_meta WHERE table_name = 'memories'");
  }

  // Build set of current file paths for orphan detection
  const currentPaths = new Set<string>();

  for (const filePath of files) {
    const meta = parseMemoryPath(filePath);
    if (!meta) continue;

    const sourcePath = relative(VAULT_STUDIO, filePath).replace(/\\/g, "/");
    currentPaths.add(sourcePath);

    const rawContent = readFileSync(filePath, "utf-8");
    const hash = hashFile(rawContent);

    // Check if already synced with same hash
    const existing = db.select().from(syncMeta).where(eq(syncMeta.sourcePath, sourcePath)).get();
    if (existing && existing.fileHash === hash && !opts?.full) continue;

    const parsed = parseFile(filePath);
    const ts = now();

    // Extract memoryType from frontmatter (episodic/semantic/entity, default null)
    const memoryType = parsed.frontmatter.memoryType || parsed.frontmatter.memory_type || null;

    // Upsert memory row
    raw.exec(`
      INSERT INTO memories (agent, tier, title, content, tags, memory_type, source_path, file_hash, created_at, updated_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      ON CONFLICT(source_path) DO UPDATE SET
        agent=excluded.agent, tier=excluded.tier, title=excluded.title,
        content=excluded.content, tags=excluded.tags, memory_type=excluded.memory_type,
        file_hash=excluded.file_hash, updated_at=excluded.updated_at
    `.trim(), [meta.agent, meta.tier, parsed.title, parsed.content, parsed.tags, memoryType, sourcePath, hash, ts, ts] as any);

    // Upsert sync meta
    raw.exec(`
      INSERT INTO sync_meta (source_path, file_hash, table_name, synced_at)
      VALUES (?, ?, 'memories', ?)
      ON CONFLICT(source_path) DO UPDATE SET
        file_hash=excluded.file_hash, synced_at=excluded.synced_at
    `.trim(), [sourcePath, hash, ts] as any);

    changed++;
  }

  // Remove orphans (files that no longer exist)
  const orphans = removeOrphans(raw, "memories", currentPaths);

  if (opts?.full) rebuildFts(raw);

  return changed + orphans;
}

// ─── Reference sync ──────────────────────────────────────────

/** Determine collection from file path */
function parseReferencePath(filePath: string): { collection: string } | null {
  const rel = relative(REFS_ROOT, filePath).replace(/\\/g, "/");
  const parts = rel.split("/");
  if (parts.length < 1) return null;
  return { collection: parts[0] };
}

/**
 * Sync all reference files into brain.db.
 * @param full - If true, drops and rebuilds. If false, incremental hash diff.
 */
export async function syncReferences(opts?: { full?: boolean }): Promise<number> {
  const db = getDb();
  const raw = getRawDb();
  const files = findMdFiles(REFS_ROOT);
  let changed = 0;

  if (opts?.full) {
    raw.exec("DELETE FROM 'references'");
    raw.exec("DELETE FROM sync_meta WHERE table_name = 'references'");
  }

  const currentPaths = new Set<string>();

  for (const filePath of files) {
    const meta = parseReferencePath(filePath);
    if (!meta) continue;

    const sourcePath = relative(VAULT_STUDIO, filePath).replace(/\\/g, "/");
    currentPaths.add(sourcePath);

    const rawContent = readFileSync(filePath, "utf-8");
    const hash = hashFile(rawContent);

    const existing = db.select().from(syncMeta).where(eq(syncMeta.sourcePath, sourcePath)).get();
    if (existing && existing.fileHash === hash && !opts?.full) continue;

    const parsed = parseFile(filePath);
    const ts = now();
    const fmJson = Object.keys(parsed.frontmatter).length > 0 ? JSON.stringify(parsed.frontmatter) : null;

    raw.exec(`
      INSERT INTO 'references' (collection, title, content, tags, frontmatter, source_path, file_hash, updated_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
      ON CONFLICT(source_path) DO UPDATE SET
        collection=excluded.collection, title=excluded.title,
        content=excluded.content, tags=excluded.tags, frontmatter=excluded.frontmatter,
        file_hash=excluded.file_hash, updated_at=excluded.updated_at
    `.trim(), [meta.collection, parsed.title, parsed.content, parsed.tags, fmJson, sourcePath, hash, ts] as any);

    raw.exec(`
      INSERT INTO sync_meta (source_path, file_hash, table_name, synced_at)
      VALUES (?, ?, 'references', ?)
      ON CONFLICT(source_path) DO UPDATE SET
        file_hash=excluded.file_hash, synced_at=excluded.synced_at
    `.trim(), [sourcePath, hash, ts] as any);

    changed++;
  }

  const orphans = removeOrphans(raw, "references", currentPaths);

  if (opts?.full) rebuildFts(raw);

  return changed + orphans;
}

// ─── Chunk + Embed sync ─────────────────────────────────────

export interface ChunkSyncResult {
  filesProcessed: number;
  chunksCreated: number;
  chunksEmbedded: number;
  chunksFailed: number;
}

/**
 * Sync reference chunks: chunk changed files and embed via Gemini.
 * Runs after syncReferences() — uses the same hash tracking.
 * Only processes files whose chunks are missing or whose hash changed.
 *
 * @param opts.full - Rebuild all chunks from scratch
 * @param opts.embedOnly - Only embed chunks that are missing embeddings (no re-chunking)
 */
export async function syncChunks(opts?: { full?: boolean; embedOnly?: boolean }): Promise<ChunkSyncResult> {
  const raw = getRawDb();
  const db = getDb();

  if (opts?.full && !opts?.embedOnly) {
    raw.exec("DELETE FROM reference_chunks");
    raw.exec("DELETE FROM vec_chunks");
  }

  // Get all reference rows with their hashes
  const refRows = raw.prepare("SELECT id, collection, title, content, tags, source_path, file_hash FROM 'references'").all() as any[];

  let filesProcessed = 0;
  let chunksCreated = 0;
  const pendingEmbeds: { chunkId: number; content: string }[] = [];

  if (!opts?.embedOnly) {
    for (const ref of refRows) {
      // Check if chunks already exist with matching hash
      const existingChunk = raw.prepare(
        "SELECT file_hash FROM reference_chunks WHERE source_path = ? LIMIT 1"
      ).get(ref.source_path) as { file_hash: string } | null;

      if (existingChunk && existingChunk.file_hash === ref.file_hash && !opts?.full) continue;

      // Delete old chunks for this file
      const oldChunkIds = raw.prepare(
        "SELECT id FROM reference_chunks WHERE source_path = ?"
      ).all(ref.source_path) as { id: number }[];

      if (oldChunkIds.length > 0) {
        raw.exec(`DELETE FROM reference_chunks WHERE source_path = ?`, [ref.source_path] as any);
        for (const { id } of oldChunkIds) {
          try { raw.exec(`DELETE FROM vec_chunks WHERE chunk_id = ?`, [id] as any); } catch {}
        }
      }

      // Chunk the file
      const fileName = ref.source_path.split("/").pop() || "unknown.md";
      const chunks = chunkMarkdown(ref.content, fileName);
      const ts = now();

      for (const chunk of chunks) {
        const result = raw.prepare(`
          INSERT INTO reference_chunks (reference_id, collection, source_path, section_name, content, line_start, line_end, tags, token_count, file_hash, created_at, updated_at)
          VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        `).run(
          ref.id, ref.collection, ref.source_path, chunk.sectionName,
          chunk.content, chunk.lineStart, chunk.lineEnd,
          ref.tags, chunk.tokenCount, ref.file_hash, ts, ts
        );

        const chunkId = Number(result.lastInsertRowid);
        pendingEmbeds.push({ chunkId, content: chunk.content });
        chunksCreated++;
      }

      filesProcessed++;
    }
  }

  // Also find chunks missing embeddings (for embedOnly mode or failed previous embeds)
  if (opts?.embedOnly) {
    const unembedded = raw.prepare(
      "SELECT id, content FROM reference_chunks WHERE embedded_at IS NULL"
    ).all() as { id: number; content: string }[];
    for (const row of unembedded) {
      pendingEmbeds.push({ chunkId: row.id, content: row.content });
    }
  }

  // Batch embed all pending chunks
  let chunksEmbedded = 0;
  let chunksFailed = 0;

  if (pendingEmbeds.length > 0) {
    const texts = pendingEmbeds.map(p => p.content);
    const result = await embedBatch(texts, "brain-sync");
    const ts = now();

    for (let i = 0; i < pendingEmbeds.length; i++) {
      const embedding = result.embeddings[i];
      if (embedding) {
        const buf = vectorToBuffer(embedding);
        raw.exec(
          "UPDATE reference_chunks SET embed_model = ?, embedded_at = ?, updated_at = ? WHERE id = ?",
          [EMBEDDING_CONFIG.model, ts, ts, pendingEmbeds[i].chunkId] as any
        );
        try {
          raw.exec(
            "INSERT INTO vec_chunks(chunk_id, embedding) VALUES (?, ?)",
            [pendingEmbeds[i].chunkId, buf] as any
          );
        } catch {
          // May already exist from a previous partial run — update instead
          raw.exec(
            "UPDATE vec_chunks SET embedding = ? WHERE chunk_id = ?",
            [buf, pendingEmbeds[i].chunkId] as any
          );
        }
        chunksEmbedded++;
      } else {
        chunksFailed++;
      }
    }
  }

  return { filesProcessed, chunksCreated, chunksEmbedded, chunksFailed };
}

/**
 * Get embedding stats across all stores.
 */
export function getEmbedStats(): {
  chunks: { total: number; embedded: number; unembedded: number };
  memories: { total: number; embedded: number; unembedded: number };
  decisions: { total: number; embedded: number; unembedded: number };
  projects: { total: number; embedded: number; unembedded: number };
  raw: { total: number; embedded: number; unembedded: number };
} {
  const raw = getRawDb();

  const chunksTotal = (raw.prepare("SELECT COUNT(*) as c FROM reference_chunks").get() as any).c;
  const chunksEmbedded = (raw.prepare("SELECT COUNT(*) as c FROM reference_chunks WHERE embedded_at IS NOT NULL").get() as any).c;

  const memTotal = (raw.prepare("SELECT COUNT(*) as c FROM memories").get() as any).c;
  const memEmbedded = (raw.prepare("SELECT COUNT(*) as c FROM memories WHERE embedded_at IS NOT NULL").get() as any).c;

  const decTotal = (raw.prepare("SELECT COUNT(*) as c FROM decisions").get() as any).c;
  const decEmbedded = (raw.prepare("SELECT COUNT(*) as c FROM decisions WHERE embedded_at IS NOT NULL").get() as any).c;

  const projTotal = (raw.prepare("SELECT COUNT(*) as c FROM project_chunks").get() as any).c;
  const projEmbedded = (raw.prepare("SELECT COUNT(*) as c FROM project_chunks WHERE embedded_at IS NOT NULL").get() as any).c;

  const rawTotal = (raw.prepare("SELECT COUNT(*) as c FROM raw_chunks").get() as any).c;
  const rawEmbedded = (raw.prepare("SELECT COUNT(*) as c FROM raw_chunks WHERE embedded_at IS NOT NULL").get() as any).c;

  return {
    chunks: { total: chunksTotal, embedded: chunksEmbedded, unembedded: chunksTotal - chunksEmbedded },
    memories: { total: memTotal, embedded: memEmbedded, unembedded: memTotal - memEmbedded },
    decisions: { total: decTotal, embedded: decEmbedded, unembedded: decTotal - decEmbedded },
    projects: { total: projTotal, embedded: projEmbedded, unembedded: projTotal - projEmbedded },
    raw: { total: rawTotal, embedded: rawEmbedded, unembedded: rawTotal - rawEmbedded },
  };
}

// ─── Project sync ───────────────────────────────────────────

/** Detect doc type from filename */
function detectDocType(fileName: string): string {
  const lower = fileName.toLowerCase();
  if (lower === "brief.md") return "brief";
  if (lower === "prd.md") return "prd";
  if (lower === "architect.md") return "architect";
  if (lower.includes("task")) return "task";
  return "tech-approach";
}

/** Detect project name from path */
function detectProject(filePath: string, root: string): string {
  const rel = relative(root, filePath).replace(/\\/g, "/");
  const parts = rel.split("/");
  // vault/studio/projects/{project-name}/file.md → project-name
  // vault/notes/docs/file.md → "freddie-ai" (internal docs)
  if (root === PROJECTS_ROOT && parts.length >= 2) return parts[0];
  return "freddie-ai";
}

/**
 * Sync project docs: chunk + embed from vault/studio/projects/ and vault/notes/docs/.
 */
export async function syncProjects(opts?: { full?: boolean }): Promise<ChunkSyncResult> {
  const raw = getRawDb();

  if (opts?.full) {
    raw.exec("DELETE FROM project_chunks");
    raw.exec("DELETE FROM vec_projects");
  }

  // Collect files from both locations
  const projectFiles = findMdFiles(PROJECTS_ROOT);
  const docFiles = findMdFiles(DOCS_ROOT);
  const allFiles = [
    ...projectFiles.map(f => ({ path: f, root: PROJECTS_ROOT })),
    ...docFiles.map(f => ({ path: f, root: DOCS_ROOT })),
  ];

  let filesProcessed = 0;
  let chunksCreated = 0;
  const pendingEmbeds: { chunkId: number; content: string }[] = [];

  for (const { path: filePath, root } of allFiles) {
    const rawContent = readFileSync(filePath, "utf-8");
    const hash = hashFile(rawContent);
    const fileName = filePath.split(/[/\\]/).pop() || "unknown.md";
    const project = detectProject(filePath, root);
    const docType = detectDocType(fileName);
    const sourcePath = relative(fromRoot(), filePath).replace(/\\/g, "/");

    // Check if chunks exist with matching hash
    const existing = raw.prepare(
      "SELECT file_hash FROM project_chunks WHERE source_path = ? LIMIT 1"
    ).get(sourcePath) as { file_hash: string } | null;

    if (existing && existing.file_hash === hash && !opts?.full) continue;

    // Delete old chunks
    const oldIds = raw.prepare(
      "SELECT id FROM project_chunks WHERE source_path = ?"
    ).all(sourcePath) as { id: number }[];

    if (oldIds.length > 0) {
      raw.exec("DELETE FROM project_chunks WHERE source_path = ?", [sourcePath] as any);
      for (const { id } of oldIds) {
        try { raw.exec("DELETE FROM vec_projects WHERE chunk_id = ?", [id] as any); } catch {}
      }
    }

    // Extract frontmatter for status
    const parsed = parseFile(filePath);
    const status = parsed.frontmatter.status ?? null;
    const tags = parsed.tags;

    // Chunk
    const chunks = chunkMarkdown(rawContent, fileName);
    const ts = now();

    for (const chunk of chunks) {
      const result = raw.prepare(`
        INSERT INTO project_chunks (project, doc_type, source_path, section_name, content, line_start, line_end, tags, status, token_count, file_hash, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      `).run(
        project, docType, sourcePath, chunk.sectionName,
        chunk.content, chunk.lineStart, chunk.lineEnd,
        tags, status, chunk.tokenCount, hash, ts, ts
      );

      const chunkId = Number(result.lastInsertRowid);
      pendingEmbeds.push({ chunkId, content: chunk.content });
      chunksCreated++;
    }

    filesProcessed++;
  }

  // Batch embed
  let chunksEmbedded = 0;
  let chunksFailed = 0;

  if (pendingEmbeds.length > 0) {
    const texts = pendingEmbeds.map(p => p.content);
    const result = await embedBatch(texts, "brain-project-sync");
    const ts = now();

    for (let i = 0; i < pendingEmbeds.length; i++) {
      const embedding = result.embeddings[i];
      if (embedding) {
        const buf = vectorToBuffer(embedding);
        raw.exec(
          "UPDATE project_chunks SET embed_model = ?, embedded_at = ?, updated_at = ? WHERE id = ?",
          [EMBEDDING_CONFIG.model, ts, ts, pendingEmbeds[i].chunkId] as any
        );
        try {
          raw.exec("INSERT INTO vec_projects(chunk_id, embedding) VALUES (?, ?)",
            [pendingEmbeds[i].chunkId, buf] as any);
        } catch {
          raw.exec("UPDATE vec_projects SET embedding = ? WHERE chunk_id = ?",
            [buf, pendingEmbeds[i].chunkId] as any);
        }
        chunksEmbedded++;
      } else {
        chunksFailed++;
      }
    }
  }

  return { filesProcessed, chunksCreated, chunksEmbedded, chunksFailed };
}

// ─── Memory + Decision batch embed ──────────────────────────

export interface BatchEmbedStoreResult {
  embedded: number;
  failed: number;
}

/**
 * Batch embed all unembedded memories.
 */
export async function embedUnembeddedMemories(): Promise<BatchEmbedStoreResult> {
  const raw = getRawDb();
  const rows = raw.prepare(
    "SELECT id, source_path, content FROM memories WHERE embedded_at IS NULL"
  ).all() as { id: number; source_path: string; content: string }[];

  if (rows.length === 0) return { embedded: 0, failed: 0 };

  const texts = rows.map(r => r.content);
  const result = await embedBatch(texts, "brain-memory-sync");
  const ts = now();
  let embedded = 0;
  let failed = 0;

  for (let i = 0; i < rows.length; i++) {
    const embedding = result.embeddings[i];
    if (embedding) {
      const buf = vectorToBuffer(embedding);
      raw.exec(
        "UPDATE memories SET embedding = ?, embed_model = ?, embedded_at = ? WHERE id = ?",
        [JSON.stringify(embedding), EMBEDDING_CONFIG.model, ts, rows[i].id] as any
      );
      try {
        raw.exec("INSERT INTO vec_memories(memory_id, embedding) VALUES (?, ?)", [rows[i].id, buf] as any);
      } catch {
        raw.exec("UPDATE vec_memories SET embedding = ? WHERE memory_id = ?", [buf, rows[i].id] as any);
      }
      embedded++;
    } else {
      failed++;
    }
  }

  return { embedded, failed };
}

/**
 * Batch embed all unembedded decisions.
 */
export async function embedUnembeddedDecisions(): Promise<BatchEmbedStoreResult> {
  const raw = getRawDb();
  const rows = raw.prepare(
    "SELECT id, decision, context, alternatives, outcome FROM decisions WHERE embedded_at IS NULL"
  ).all() as { id: number; decision: string; context: string; alternatives: string | null; outcome: string | null }[];

  if (rows.length === 0) return { embedded: 0, failed: 0 };

  // Build embed text: decision + context + alternatives + outcome
  const texts = rows.map(r => {
    const parts = [r.decision, `Context: ${r.context}`];
    if (r.alternatives) parts.push(`Alternatives: ${r.alternatives}`);
    if (r.outcome) parts.push(`Outcome: ${r.outcome}`);
    return parts.join(". ");
  });

  const result = await embedBatch(texts, "brain-decision-sync");
  const ts = now();
  let embedded = 0;
  let failed = 0;

  for (let i = 0; i < rows.length; i++) {
    const embedding = result.embeddings[i];
    if (embedding) {
      const buf = vectorToBuffer(embedding);
      raw.exec(
        "UPDATE decisions SET embedding = ?, embed_model = ?, embedded_at = ? WHERE id = ?",
        [JSON.stringify(embedding), EMBEDDING_CONFIG.model, ts, rows[i].id] as any
      );
      try {
        raw.exec("INSERT INTO vec_decisions(decision_id, embedding) VALUES (?, ?)", [rows[i].id, buf] as any);
      } catch {
        raw.exec("UPDATE vec_decisions SET embedding = ? WHERE decision_id = ?", [buf, rows[i].id] as any);
      }
      embedded++;
    } else {
      failed++;
    }
  }

  return { embedded, failed };
}

// ─── Shared ──────────────────────────────────────────────────

/** Remove rows whose source files no longer exist on disk */
function removeOrphans(raw: import("bun:sqlite").Database, tableName: string, currentPaths: Set<string>): number {
  const table = tableName === "references" ? "'references'" : tableName;
  const rows = raw.prepare(`SELECT source_path FROM ${table}`).all() as { source_path: string }[];
  let removed = 0;

  for (const row of rows) {
    if (!currentPaths.has(row.source_path)) {
      raw.exec(`DELETE FROM ${table} WHERE source_path = ?`, [row.source_path] as any);
      raw.exec(`DELETE FROM sync_meta WHERE source_path = ?`, [row.source_path] as any);
      removed++;
    }
  }

  return removed;
}

/**
 * Quick check — counts how many files have changed since last sync
 * without actually syncing. Fast for boot checks.
 */
export async function checkSync(): Promise<SyncStatus> {
  const db = getDb();
  let memoriesChanged = 0;
  let memoriesTotal = 0;
  let refsChanged = 0;
  let refsTotal = 0;
  let removed = 0;

  // Check memory files
  const memFiles = findMdFiles(MEMORY_ROOT);
  const memPaths = new Set<string>();
  for (const filePath of memFiles) {
    const meta = parseMemoryPath(filePath);
    if (!meta) continue;
    memoriesTotal++;

    const sourcePath = relative(VAULT_STUDIO, filePath).replace(/\\/g, "/");
    memPaths.add(sourcePath);

    const rawContent = readFileSync(filePath, "utf-8");
    const hash = hashFile(rawContent);
    const existing = db.select().from(syncMeta).where(eq(syncMeta.sourcePath, sourcePath)).get();
    if (!existing || existing.fileHash !== hash) memoriesChanged++;
  }

  // Check reference files
  const refFiles = findMdFiles(REFS_ROOT);
  const refPaths = new Set<string>();
  for (const filePath of refFiles) {
    const meta = parseReferencePath(filePath);
    if (!meta) continue;
    refsTotal++;

    const sourcePath = relative(VAULT_STUDIO, filePath).replace(/\\/g, "/");
    refPaths.add(sourcePath);

    const rawContent = readFileSync(filePath, "utf-8");
    const hash = hashFile(rawContent);
    const existing = db.select().from(syncMeta).where(eq(syncMeta.sourcePath, sourcePath)).get();
    if (!existing || existing.fileHash !== hash) refsChanged++;
  }

  // Count orphans in sync_meta
  const allSyncRows = raw_allSyncPaths(db);
  for (const row of allSyncRows) {
    if (row.tableName === "memories" && !memPaths.has(row.sourcePath)) removed++;
    if (row.tableName === "references" && !refPaths.has(row.sourcePath)) removed++;
  }

  return { memoriesChanged, memoriesTotal, refsChanged, refsTotal, removed };
}

function raw_allSyncPaths(db: ReturnType<typeof getDb>) {
  return db.select({ sourcePath: syncMeta.sourcePath, tableName: syncMeta.tableName }).from(syncMeta).all();
}

