#!/usr/bin/env bun
/**
 * brain.ts — SQLite + FTS5 brain for memory/reference lookup and decision tracking
 *
 * Dual-mode: CLI (`bun src/tools/brain.ts --sync`) or native tool via registry.
 * Provides fast full-text search across vault memory and reference files,
 * plus decision logging with outcome tracking.
 */

import { z } from "zod";
import type { ToolDefinition } from "../registry/types.js";
import {
  initBrain,
  shutdownBrain,
  syncMemories,
  syncReferences,
  checkSync,
  searchMemories,
  searchReferences,
  searchDecisions,
  logDecision,
  updateOutcome,
  getDecisionHistory,
  getStats,
  setMemoryEmbedding,
  hybridSearchMemories,
  upsertEntity,
  addEntityRelation,
  getEntity,
  searchEntities,
  getEntityRelations,
  getEntityStats,
  syncChunks,
  syncProjects,
  syncRaw,
  getEmbedStats,
  embedUnembeddedMemories,
  embedUnembeddedDecisions,
  hybridSearchChunks,
  hybridSearchDecisions,
  searchAll,
  hybridSearchRaw,
  searchRecall,
} from "../libs/brain/index.js";
import { embedText, EMBEDDING_CONFIG } from "../libs/embeddings.js";
import { isEmbeddingStale } from "../libs/brain/degradation.js";

// ── Core functions ────────────────────────────────────────────

async function runSync(opts: { full?: boolean; refs?: boolean; memory?: boolean; embed?: boolean }): Promise<string> {
  initBrain();
  const lines: string[] = [];

  const doMemory = opts.memory || (!opts.memory && !opts.refs);
  const doRefs = opts.refs || (!opts.memory && !opts.refs);

  if (doMemory) {
    const count = await syncMemories({ full: opts.full });
    lines.push(`Memories: ${count} files synced`);
  }
  if (doRefs) {
    const count = await syncReferences({ full: opts.full });
    lines.push(`References: ${count} files synced`);
  }

  // Chunk + embed if --embed flag
  if (opts.embed) {
    if (doRefs) {
      const result = await syncChunks({ full: opts.full });
      lines.push(`Chunks: ${result.filesProcessed} files → ${result.chunksCreated} chunks, ${result.chunksEmbedded} embedded${result.chunksFailed > 0 ? `, ${result.chunksFailed} failed` : ""}`);
    }
    if (doMemory) {
      const memResult = await embedUnembeddedMemories();
      if (memResult.embedded > 0 || memResult.failed > 0) {
        lines.push(`Memory embeddings: ${memResult.embedded} embedded${memResult.failed > 0 ? `, ${memResult.failed} failed` : ""}`);
      }
    }
    const decResult = await embedUnembeddedDecisions();
    if (decResult.embedded > 0 || decResult.failed > 0) {
      lines.push(`Decision embeddings: ${decResult.embedded} embedded${decResult.failed > 0 ? `, ${decResult.failed} failed` : ""}`);
    }
    // Project docs
    const projResult = await syncProjects({ full: opts.full });
    if (projResult.filesProcessed > 0 || projResult.chunksCreated > 0) {
      lines.push(`Projects: ${projResult.filesProcessed} files → ${projResult.chunksCreated} chunks, ${projResult.chunksEmbedded} embedded${projResult.chunksFailed > 0 ? `, ${projResult.chunksFailed} failed` : ""}`);
    }

    // Raw context files
    const rawResult = await syncRaw({ full: opts.full });
    if (rawResult.filesProcessed > 0 || rawResult.chunksCreated > 0) {
      lines.push(`Raw: ${rawResult.filesProcessed} files → ${rawResult.chunksCreated} chunks, ${rawResult.chunksEmbedded} embedded${rawResult.chunksFailed > 0 ? `, ${rawResult.chunksFailed} failed` : ""}`);
    }
  }

  return lines.join("\n");
}

async function runReEmbed(): Promise<string> {
  initBrain();
  const raw = (await import("../libs/sqlite.js")).getRawDb();
  const lines: string[] = [];

  // Count stale embeddings across all stores
  const staleChunks = (raw.prepare("SELECT COUNT(*) as c FROM reference_chunks WHERE embed_model != ? OR embed_model IS NULL").get(EMBEDDING_CONFIG.model) as any).c;
  const staleMems = (raw.prepare("SELECT COUNT(*) as c FROM memories WHERE (embed_model != ? OR embed_model IS NULL) AND embedded_at IS NOT NULL").get(EMBEDDING_CONFIG.model) as any).c;
  const staleDecs = (raw.prepare("SELECT COUNT(*) as c FROM decisions WHERE (embed_model != ? OR embed_model IS NULL) AND embedded_at IS NOT NULL").get(EMBEDDING_CONFIG.model) as any).c;
  const staleProjs = (raw.prepare("SELECT COUNT(*) as c FROM project_chunks WHERE embed_model != ? OR embed_model IS NULL").get(EMBEDDING_CONFIG.model) as any).c;

  const total = staleChunks + staleMems + staleDecs + staleProjs;
  if (total === 0) {
    return `All embeddings are current (model: ${EMBEDDING_CONFIG.model}). Nothing to re-embed.`;
  }

  lines.push(`Stale embeddings (model != ${EMBEDDING_CONFIG.model}):`);
  if (staleChunks > 0) lines.push(`  Reference chunks: ${staleChunks}`);
  if (staleMems > 0) lines.push(`  Memories: ${staleMems}`);
  if (staleDecs > 0) lines.push(`  Decisions: ${staleDecs}`);
  if (staleProjs > 0) lines.push(`  Project docs: ${staleProjs}`);
  lines.push(`  Total: ${total}`);
  lines.push("");

  // Re-embed by running full sync with embed
  if (staleChunks > 0) {
    const r = await syncChunks({ full: true });
    lines.push(`Re-embedded ${r.chunksEmbedded} reference chunks`);
  }
  if (staleMems > 0) {
    // Clear embedded_at to force re-embed
    raw.exec("UPDATE memories SET embedded_at = NULL WHERE embed_model != ? OR embed_model IS NULL", [EMBEDDING_CONFIG.model] as any);
    const r = await embedUnembeddedMemories();
    lines.push(`Re-embedded ${r.embedded} memories`);
  }
  if (staleDecs > 0) {
    raw.exec("UPDATE decisions SET embedded_at = NULL WHERE embed_model != ? OR embed_model IS NULL", [EMBEDDING_CONFIG.model] as any);
    const r = await embedUnembeddedDecisions();
    lines.push(`Re-embedded ${r.embedded} decisions`);
  }
  if (staleProjs > 0) {
    const r = await syncProjects({ full: true });
    lines.push(`Re-embedded ${r.chunksEmbedded} project chunks`);
  }

  return lines.join("\n");
}

/**
 * Get full context from brain.db — returns chunk/memory/decision content,
 * not just scores. This replaces the need to Read files from disk.
 */
async function runGetContext(query: string, opts: {
  agent?: string;
  collection?: string;
  stores?: string;
  limit?: number;
}): Promise<string> {
  initBrain();
  const queryEmb = await embedText(query, "brain-get-context");
  const limit = opts.limit ?? 8;
  const storeList = opts.stores?.split(",") ?? ["refs", "memories", "decisions"];

  const lines: string[] = [];

  if (storeList.includes("refs")) {
    const refs = hybridSearchChunks(query, queryEmb, { collection: opts.collection, limit });
    if (refs.length > 0) {
      lines.push("=== REFERENCES ===\n");
      for (const r of refs) {
        lines.push(`--- [${r.combinedScore.toFixed(2)}] ${r.sourcePath} → ${r.sectionName} ---`);
        lines.push(r.content);
        lines.push("");
      }
    }
  }

  if (storeList.includes("memories")) {
    const mems = (await import("../libs/brain/index.js")).hybridSearchMemories(query, queryEmb, { agent: opts.agent, limit });
    if (mems.length > 0) {
      lines.push("=== MEMORIES ===\n");
      const raw = (await import("../libs/sqlite.js")).getRawDb();
      for (const m of mems) {
        const row = raw.prepare("SELECT content FROM memories WHERE source_path = ?").get(m.sourcePath) as { content: string } | null;
        if (row) {
          lines.push(`--- [${m.combinedScore.toFixed(2)}] ${m.sourcePath} (${m.agent}) ---`);
          lines.push(row.content);
          lines.push("");
        }
      }
    }
  }

  if (storeList.includes("decisions")) {
    const decs = (await import("../libs/brain/index.js")).hybridSearchDecisions(query, queryEmb, { agent: opts.agent, limit });
    if (decs.length > 0) {
      lines.push("=== DECISIONS ===\n");
      for (const d of decs) {
        lines.push(`--- [${d.combinedScore.toFixed(2)}] ${d.agent}: ${d.decision} ---`);
        lines.push(`Context: ${d.context}`);
        if (d.outcome) lines.push(`Outcome: ${d.outcome}`);
        lines.push("");
      }
    }
  }

  if (storeList.includes("projects")) {
    const projs = (await import("../libs/brain/index.js")).hybridSearchProjects(query, queryEmb, { limit });
    if (projs.length > 0) {
      lines.push("=== PROJECTS ===\n");
      for (const p of projs) {
        lines.push(`--- [${p.combinedScore.toFixed(2)}] ${p.sourcePath} → ${p.sectionName} [${p.docType}] ---`);
        lines.push(p.content);
        lines.push("");
      }
    }
  }

  if (lines.length === 0) return "No relevant context found.";
  return lines.join("\n");
}

function runEmbedStats(): string {
  initBrain();
  const stats = getEmbedStats();
  return [
    `Reference chunks: ${stats.chunks.embedded}/${stats.chunks.total} embedded${stats.chunks.unembedded > 0 ? ` (${stats.chunks.unembedded} pending)` : ""}`,
    `Memories: ${stats.memories.embedded}/${stats.memories.total} embedded${stats.memories.unembedded > 0 ? ` (${stats.memories.unembedded} pending)` : ""}`,
    `Decisions: ${stats.decisions.embedded}/${stats.decisions.total} embedded${stats.decisions.unembedded > 0 ? ` (${stats.decisions.unembedded} pending)` : ""}`,
    `Project docs: ${stats.projects.embedded}/${stats.projects.total} embedded${stats.projects.unembedded > 0 ? ` (${stats.projects.unembedded} pending)` : ""}`,
  ].join("\n");
}

async function runCheck(): Promise<string> {
  initBrain();
  const status = await checkSync();
  const lines = [
    `Memories: ${status.memoriesChanged}/${status.memoriesTotal} changed`,
    `References: ${status.refsChanged}/${status.refsTotal} changed`,
  ];
  if (status.removed > 0) lines.push(`Orphans: ${status.removed} to remove`);

  if (status.memoriesChanged > 0 || status.refsChanged > 0 || status.removed > 0) {
    // Auto-sync changed files
    if (status.memoriesChanged > 0) await syncMemories();
    if (status.refsChanged > 0) await syncReferences();
    lines.push("Auto-synced changes.");
  } else {
    lines.push("Everything up to date.");
  }

  return lines.join("\n");
}

function runQuery(query: string, opts: { type?: string; agent?: string; collection?: string; limit?: number }): string {
  initBrain();
  const limit = opts.limit ?? 10;
  const type = opts.type ?? "memories";

  if (type === "references" || type === "refs") {
    const results = searchReferences(query, { collection: opts.collection, limit });
    if (results.length === 0) return `No reference matches for "${query}"`;
    return results
      .map((r, i) => `${i + 1}. [${r.collection}] ${r.title}\n   ${r.snippet}\n   → ${r.sourcePath}`)
      .join("\n\n");
  }

  if (type === "decisions") {
    const results = searchDecisions(query, { agent: opts.agent, limit });
    if (results.length === 0) return `No decision matches for "${query}"`;
    return results
      .map(
        (r, i) =>
          `${i + 1}. [${r.agent}] ${r.decision}\n   Context: ${r.context}\n   Outcome: ${r.outcome ?? "(pending)"} | Confidence: ${r.confidence} → ${r.decayedConfidence} (decayed)`,
      )
      .join("\n\n");
  }

  // Default: memories
  const results = searchMemories(query, { agent: opts.agent, tier: opts.type === "inbox" ? "inbox" : opts.type === "knowledge" ? "knowledge" : undefined, limit });
  if (results.length === 0) return `No memory matches for "${query}"`;
  return results
    .map((r, i) => `${i + 1}. [${r.agent}/${r.tier}] ${r.title}\n   ${r.snippet}\n   → ${r.sourcePath}`)
    .join("\n\n");
}

function runDecide(agent: string, decision: string, context: string, alternatives?: string, tags?: string): string {
  initBrain();
  const id = logDecision({ agent, decision, context, alternatives, tags });
  return `Decision #${id} logged for ${agent}`;
}

function runRecall(agent: string, opts: { pattern?: string; limit?: number }): string {
  initBrain();

  if (opts.pattern) {
    const results = searchDecisions(opts.pattern, { agent, limit: opts.limit });
    if (results.length === 0) return `No decisions matching "${opts.pattern}" for ${agent}`;
    return results
      .map(
        (r, i) =>
          `${i + 1}. [#${r.id}] ${r.decision}\n   Context: ${r.context}\n   Outcome: ${r.outcome ?? "(pending)"} | Confidence: ${r.confidence} → ${r.decayedConfidence} (decayed)`,
      )
      .join("\n\n");
  }

  const history = getDecisionHistory(agent, { limit: opts.limit });
  if (history.length === 0) return `No decisions found for ${agent}`;
  return history
    .map(
      (r, i) =>
        `${i + 1}. [#${r.id}] ${r.decision}\n   ${r.createdAt} | Confidence: ${r.confidence} → ${r.decayedConfidence} (decayed)`,
    )
    .join("\n\n");
}

function runOutcome(id: number, outcome: string, confidence: number): string {
  initBrain();
  updateOutcome(id, outcome, confidence);
  return `Decision #${id} updated — confidence: ${confidence}`;
}

async function runEmbed(): Promise<string> {
  initBrain();
  const raw = (await import("../libs/sqlite.js")).getRawDb();

  // Find memories without embeddings
  const rows = raw.prepare(
    "SELECT id, source_path, title, content FROM memories WHERE embedding IS NULL"
  ).all() as { id: number; source_path: string; title: string; content: string }[];

  if (rows.length === 0) return "All memories already have embeddings.";

  const lines: string[] = [`Embedding ${rows.length} memories...`];
  let count = 0;

  for (const row of rows) {
    // Use title + first 500 chars of content for embedding (efficient + representative)
    const text = `${row.title}\n${row.content.slice(0, 500)}`;
    try {
      const embedding = await embedText(text, "brain-embed");
      setMemoryEmbedding(row.source_path, embedding);
      count++;
    } catch (err: any) {
      lines.push(`  Skip: ${row.source_path} — ${err.message}`);
    }
  }

  lines.push(`Embedded ${count}/${rows.length} memories.`);
  return lines.join("\n");
}

async function runHybridQuery(query: string, opts: { agent?: string; memoryType?: string; limit?: number }): Promise<string> {
  initBrain();
  const limit = opts.limit ?? 10;

  // Generate query embedding
  const queryEmbedding = await embedText(query, "brain-query");

  const results = hybridSearchMemories(query, queryEmbedding, {
    agent: opts.agent,
    memoryType: opts.memoryType,
    limit,
  });

  if (results.length === 0) return `No matches for "${query}"`;

  return results
    .map((r, i) => {
      const fts = r.ftsRank != null ? `FTS:${r.ftsRank.toFixed(2)}` : "FTS:—";
      const vec = r.similarity != null ? `Vec:${r.similarity.toFixed(3)}` : "Vec:—";
      return `${i + 1}. [${r.agent}] ${r.title}\n   ${fts} | ${vec} | Combined: ${r.combinedScore.toFixed(3)}\n   → ${r.sourcePath}`;
    })
    .join("\n\n");
}

function runEntityLookup(name: string): string {
  initBrain();
  const entity = getEntity(name);
  if (!entity) return `Entity "${name}" not found.`;

  const relations = getEntityRelations(entity.id);
  const lines = [
    `=== ENTITY: ${entity.name} ===`,
    `Type: ${entity.type}`,
    entity.summary ? `Summary: ${entity.summary}` : "",
    "",
  ];

  if (relations.length > 0) {
    lines.push("Relations:");
    for (const r of relations) {
      const direction = r.sourceName === entity.name
        ? `→ ${r.relation} → ${r.targetName}`
        : `← ${r.relation} ← ${r.sourceName}`;
      lines.push(`  ${direction} (weight: ${r.weight})`);
    }
  } else {
    lines.push("No relations found.");
  }

  return lines.filter(Boolean).join("\n");
}

function runEntitySearch(query: string, opts?: { type?: string }): string {
  initBrain();
  const results = searchEntities(query, { type: opts?.type });
  if (results.length === 0) return `No entities matching "${query}"`;

  return results
    .map((e, i) => `${i + 1}. [${e.type}] ${e.name}${e.summary ? ` — ${e.summary}` : ""}`)
    .join("\n");
}

function runStats(): string {
  initBrain();
  const s = getStats();
  const e = getEntityStats();
  return [
    `Memories:   ${s.memories}`,
    `References: ${s.references}`,
    `Decisions:  ${s.decisions}`,
    `Entities:   ${e.entities} (${e.relations} relations)`,
    `Agents:     ${s.agents.join(", ")}`,
    `Last sync:  ${s.lastSync ?? "never"}`,
  ].join("\n");
}

// ── Tool definition ───────────────────────────────────────────

export const toolDef: ToolDefinition = {
  name: "brain",
  description:
    "Fast memory/reference search and decision tracking via SQLite + FTS5. " +
    "Actions: sync (index files), check (incremental sync), query (FTS search), " +
    "decide (log decision), recall (search decisions), outcome (update result), stats.",
  inputSchema: z.object({
    action: z
      .enum(["sync", "check", "query", "decide", "recall", "outcome", "stats"])
      .describe("Action to perform"),
    query: z.string().optional().describe("Search query (for query/recall actions)"),
    type: z
      .enum(["memories", "references", "refs", "decisions", "inbox", "knowledge"])
      .optional()
      .describe("Search type (default: memories)"),
    agent: z.string().optional().describe("Filter by agent name"),
    collection: z.string().optional().describe("Filter references by collection (suno/minimax/lyrics/shared)"),
    decision: z.string().optional().describe("Decision text (for decide action)"),
    context: z.string().optional().describe("Decision context (for decide action)"),
    alternatives: z.string().optional().describe("Alternatives considered (for decide action)"),
    outcome: z.string().optional().describe("Outcome text (for outcome action)"),
    confidence: z.number().optional().describe("Confidence 0.0-1.0 (for outcome action)"),
    id: z.number().optional().describe("Decision ID (for outcome action)"),
    tags: z.string().optional().describe("Comma-separated tags"),
    limit: z.number().optional().describe("Max results (default: 10)"),
    full: z.boolean().optional().describe("Full rebuild (for sync action)"),
    refs: z.boolean().optional().describe("Sync references only (for sync action)"),
    memory: z.boolean().optional().describe("Sync memories only (for sync action)"),
  }),
  tags: ["memory", "reference", "utility"],
  execute: async (args) => {
    try {
      let output: string;

      switch (args.action) {
        case "sync":
          output = await runSync({ full: args.full, refs: args.refs, memory: args.memory });
          break;
        case "check":
          output = await runCheck();
          break;
        case "query":
          if (!args.query) return { output: "Missing required: query", isError: true };
          output = runQuery(args.query, {
            type: args.type,
            agent: args.agent,
            collection: args.collection,
            limit: args.limit,
          });
          break;
        case "decide":
          if (!args.agent || !args.decision || !args.context)
            return { output: "Missing required: agent, decision, context", isError: true };
          output = runDecide(args.agent, args.decision, args.context, args.alternatives, args.tags);
          break;
        case "recall":
          if (!args.agent) return { output: "Missing required: agent", isError: true };
          output = runRecall(args.agent, { pattern: args.query, limit: args.limit });
          break;
        case "outcome":
          if (args.id == null || !args.outcome || args.confidence == null)
            return { output: "Missing required: id, outcome, confidence", isError: true };
          output = runOutcome(args.id, args.outcome, args.confidence);
          break;
        case "stats":
          output = runStats();
          break;
        default:
          output = `Unknown action: ${args.action}`;
      }

      return { output };
    } catch (err: any) {
      return { output: `[brain error] ${err.message}`, isError: true };
    }
  },
};

