      console.log("  --get-context <term> [--agent A] [--stores refs,memories,decisions,projects] [--limit N]");
      console.log("                                           Full content retrieval — replaces file reads");
      console.log("  --hybrid <term> [--agent A]             Hybrid search on memories");
      console.log("  --embed                                  Generate embeddings for all memories");
      console.log("  --entity <name>                          Lookup entity + relations");
      console.log("  --entity-search <query> [--entity-type T]  Search entities");
      console.log("  --entity-add <name> --entity-type <type>   Add/update entity");
      console.log("  --entity-link --source A --target B --relation R");
      console.log("  --decide --agent A --decision D --context C");
      console.log("  --recall-all <query> [--skill S]        Cross-store search INCLUDING raw (conversational recall)");
      console.log("  --search-raw <query> [--skill S]        Search raw context only (eidetic lookup)");
      console.log("  --recall --agent A [--pattern P]        Search past decisions (agent-scoped)");
      console.log("  --outcome --id N --result R --confidence C");
      console.log("  --stats                                  Show brain.db stats");
    }
  } catch (err: any) {
    console.error(`[brain error] ${err.message}`);
    process.exit(1);
  } finally {
    shutdownBrain();
  }
}

